const wh = ($('POST /attach-analyze').first().json.body) || {};
const resp = $json || {};
let summary = '';
try { summary = (resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content) || ''; } catch (e) {}
if (!summary) summary = 'Attachment received, but it could not be analysed automatically.';
const esc = (s) => String(s == null ? '' : s).replace(/'/g, "''");
return [{ json: { session_id: esc(wh.session_id || 'anon'), filename: esc(wh.filename || 'file'), mime: esc(wh.mime || ''), summary: esc(summary), summary_raw: summary } }];
